const I18N={"Lessen": {"tr": "Dersler", "en": "Lessons"}, "Lezingen": {"tr": "Konferanslar", "en": "Lectures"}, "Workshops": {"tr": "Atölyeler", "en": "Workshops"}, "Arabisch & Tadjwied": {"tr": "Arapça ve Tecvid", "en": "Arabic & Tajwid"}, "Nederlandstalige lezingen voor dames": {"tr": "Hanımlar için Hollandaca dersler", "en": "Dutch-language lectures for women"}, "Praktijkgerichte workshops": {"tr": "Uygulamalı atölyeler", "en": "Practice-based workshops"}, "De reis van de ziel": {"tr": "Ruhun yolculuğu", "en": "The journey of the soul"}, "Home": {"tr": "Ana sayfa", "en": "Home"}, "Over mij": {"tr": "Hakkımda", "en": "About me"}, "Begeleiding": {"tr": "Manevi danışmanlık", "en": "Spiritual care"}, "Diensten & Aanbod": {"tr": "Hizmetlerimiz", "en": "Services & Offerings"}, "Materialen": {"tr": "Materyaller", "en": "Materials"}, "Publicaties": {"tr": "Yayınlar", "en": "Publications"}, "Contact": {"tr": "İletişim", "en": "Contact"}, "Plan een consult": {"tr": "Görüşme planlayın", "en": "Book a consultation"}, "› De reis van de ziel ‹": {"tr": "› Ruhun yolculuğu ‹", "en": "› The journey of the soul ‹"}, "Rihlaturruh · De reis van de ziel": {"tr": "Rihlaturruh · Ruhun yolculuğu", "en": "Rihlaturruh · The journey of the soul"}, "Een plek voor islamitische reflectie, geestelijke verzorging, publicaties en zorgvuldig ontwikkelde materialen die bijdragen aan bezinning, betekenis en innerlijke rust.": {"tr": "İslami tefekkür, manevi danışmanlık, yayınlar ve özenle hazırlanmış materyaller için bir alan; tefekküre, anlama ve iç huzura katkı sunar.", "en": "A place for Islamic reflection, spiritual care, publications and carefully developed materials that contribute to contemplation, meaning and inner peace."}, "Bekijk de publicaties →": {"tr": "Yayınlara göz atın →", "en": "View the publications →"}, "Wat je hier kunt vinden": {"tr": "Burada neler bulabilirsiniz", "en": "What you can find here"}, "Persoonlijke geestelijke verzorging vanuit islamitisch perspectief.": {"tr": "İslami perspektiften kişiye özel manevi danışmanlık.", "en": "Personal spiritual care from an Islamic perspective."}, "Lees meer →": {"tr": "Devamını okuyun →", "en": "Read more →"}, "Werkbladen, posters en digitale hulpmiddelen voor persoonlijk en professioneel gebruik.": {"tr": "Kişisel ve profesyonel kullanım için çalışma sayfaları, posterler ve dijital araçlar.", "en": "Worksheets, posters and digital tools for personal and professional use."}, "Ontdek de materialen →": {"tr": "Materyalleri keşfedin →", "en": "Discover the materials →"}, "Samenvattingen van scripties, onderzoek en het dashboard van het masteronderzoek.": {"tr": "Tez özetleri, araştırmalar ve yüksek lisans araştırmasının paneli.", "en": "Thesis summaries, research and the dashboard of the master's research."}, "Onze visie": {"tr": "Vizyonumuz", "en": "Our vision"}, "Wij geloven dat geestelijke groei begint wanneer er ruimte ontstaat voor stilte, reflectie en oprechte verbinding met Allah.": {"tr": "Manevi gelişimin; sükûnete, tefekküre ve Allah ile samimi bir bağa alan açıldığında başladığına inanıyoruz.", "en": "We believe that spiritual growth begins when there is room for stillness, reflection and a sincere connection with Allah."}, "Rihlaturruh wil bijdragen aan die reis door kennis, bezinning en praktische hulpmiddelen aan te bieden die mensen ondersteunen in het dagelijks leven, zowel persoonlijk als professioneel.": {"tr": "Rihlaturruh; bilgi, tefekkür ve pratik araçlar sunarak insanları hem kişisel hem de profesyonel olarak günlük hayatlarında desteklemeyi ve bu yolculuğa katkı sunmayı amaçlar.", "en": "Rihlaturruh aims to contribute to that journey by offering knowledge, contemplation and practical tools that support people in daily life, both personally and professionally."}, "Meer over onze visie →": {"tr": "Vizyonumuz hakkında daha fazlası →", "en": "More about our vision →"}, "Rihlaturruh betekent: de reis van de ziel. Een uitnodiging om niet alleen verder te gaan, maar ook stil te staan.": {"tr": "Rihlaturruh, ruhun yolculuğu demektir. Yalnızca yola devam etmeye değil, aynı zamanda durup düşünmeye de bir davet.", "en": "Rihlaturruh means: the journey of the soul. An invitation not only to move forward, but also to pause."}, "Over Rihlaturruh": {"tr": "Rihlaturruh hakkında", "en": "About Rihlaturruh"}, "Rihlaturruh betekent de reis van de ziel.": {"tr": "Rihlaturruh, ruhun yolculuğu demektir.", "en": "Rihlaturruh means the journey of the soul."}, "Iedere ziel bewandelt een eigen weg. Een weg waarop momenten van vreugde, beproeving, groei en bezinning elkaar afwisselen. Tijdens deze reis ontstaat soms de behoefte om stil te staan, richting te vinden of woorden te geven aan wat zich in het hart afspeelt.": {"tr": "Her ruh kendi yolunu yürür. Sevinç, imtihan, gelişim ve tefekkür anlarının birbirini izlediği bir yol. Bu yolculukta kimi zaman durup düşünme, yön bulma ya da kalpte olan biteni kelimelere dökme ihtiyacı doğar.", "en": "Every soul walks its own path — a path where moments of joy, trial, growth and contemplation alternate. Along this journey there sometimes arises a need to pause, to find direction, or to put into words what is happening in the heart."}, "Rihlaturruh is ontstaan vanuit de wens om ruimte te bieden voor die innerlijke reis. Vanuit een islamitisch-theologische achtergrond en professionele ervaring in de islamitische geestelijke verzorging ontwikkelt Rihlaturruh materialen, publicaties en begeleiding die bijdragen aan reflectie, betekenisgeving en een bewuste verbinding met Allah.": {"tr": "Rihlaturruh, bu içsel yolculuğa alan açma arzusundan doğdu. İslami ilahiyat altyapısı ve İslami manevi danışmanlık alanındaki profesyonel deneyimden hareketle Rihlaturruh; tefekküre, anlam kazandırmaya ve Allah ile bilinçli bir bağa katkı sunan materyaller, yayınlar ve danışmanlık geliştirir.", "en": "Rihlaturruh arose from the wish to create space for that inner journey. From a background in Islamic theology and professional experience in Islamic spiritual care, Rihlaturruh develops materials, publications and guidance that contribute to reflection, meaning-making and a conscious connection with Allah."}, "Waar verdieping begint": {"tr": "Derinleşmenin başladığı yer", "en": "Where depth begins"}, "Wij geloven dat ware groei begint in het hart. Wanneer we bewust leren stilstaan bij onze ervaringen, onze relatie met Allah en onze plaats in het leven, ontstaat ruimte voor innerlijke rust, veerkracht en betekenis.": {"tr": "Gerçek gelişimin kalpte başladığına inanıyoruz. Deneyimlerimiz, Allah ile ilişkimiz ve hayattaki yerimiz üzerine bilinçli biçimde durmayı öğrendiğimizde; iç huzura, dayanıklılığa ve anlama alan açılır.", "en": "We believe that true growth begins in the heart. When we consciously learn to pause and consider our experiences, our relationship with Allah and our place in life, room emerges for inner peace, resilience and meaning."}, "Vanuit deze overtuiging ontwikkelt Rihlaturruh zorgvuldig vormgegeven materialen, biedt het geestelijke verzorging en deelt het kennis en onderzoek die uitnodigen tot reflectie, bewustwording en verdieping. Elk onderdeel draagt bij aan hetzelfde doel: mensen ondersteunen tijdens hun eigen reis van de ziel.": {"tr": "Bu inançtan hareketle Rihlaturruh özenle hazırlanmış materyaller geliştirir, manevi danışmanlık sunar ve tefekküre, farkındalığa ve derinleşmeye davet eden bilgi ve araştırmaları paylaşır. Her bir unsur aynı amaca hizmet eder: insanları kendi ruh yolculuklarında desteklemek.", "en": "From this conviction, Rihlaturruh develops carefully designed materials, offers spiritual care, and shares knowledge and research that invite reflection, awareness and depth. Every part serves the same purpose: supporting people on their own journey of the soul."}, "Alles wat binnen Rihlaturruh wordt ontwikkeld, vindt zijn inspiratie in de Koran, de authentieke Soennah en de rijke islamitische traditie van": {"tr": "Rihlaturruh bünyesinde geliştirilen her şey ilhamını Kur'an'dan, sahih Sünnet'ten ve zengin İslami gelenekten alır:", "en": "Everything developed within Rihlaturruh draws its inspiration from the Qur'an, the authentic Sunnah and the rich Islamic tradition of"}, "(de zuivering van de ziel). Door geloof, wetenschap en praktijk met elkaar te verbinden, wil Rihlaturruh bijdragen aan een bewuste en betekenisvolle levenshouding.": {"tr": "(nefsin arındırılması). Rihlaturruh; imanı, ilmi ve pratiği birbirine bağlayarak bilinçli ve anlamlı bir hayat duruşuna katkı sunmayı amaçlar.", "en": "(the purification of the soul). By connecting faith, scholarship and practice, Rihlaturruh seeks to contribute to a conscious and meaningful way of living."}, "Voor wie is Rihlaturruh?": {"tr": "Rihlaturruh kimler için?", "en": "Who is Rihlaturruh for?"}, "Voor iedereen die verdieping zoekt": {"tr": "Derinleşme arayan herkes için", "en": "For everyone seeking depth"}, "Rihlaturruh is er voor iedereen die verlangt naar verdieping vanuit een islamitisch perspectief. Door middel van geestelijke verzorging, reflectiematerialen en publicaties wil Rihlaturruh bijdragen aan bezinning, kennis en persoonlijke groei.": {"tr": "Rihlaturruh, İslami perspektiften derinleşmeyi arzulayan herkes içindir. Manevi danışmanlık, tefekkür materyalleri ve yayınlar aracılığıyla Rihlaturruh; tefekküre, bilgiye ve kişisel gelişime katkı sunmayı amaçlar.", "en": "Rihlaturruh is for everyone who longs for depth from an Islamic perspective. Through spiritual care, reflection materials and publications, Rihlaturruh aims to contribute to contemplation, knowledge and personal growth."}, "Rihlaturruh richt zich onder andere op:": {"tr": "Rihlaturruh özellikle şunlara yöneliktir:", "en": "Rihlaturruh is aimed at, among others:"}, "Mensen die op zoek zijn naar persoonlijke reflectie en spirituele ontwikkeling": {"tr": "Kişisel tefekkür ve manevi gelişim arayan kişiler", "en": "People seeking personal reflection and spiritual development"}, "Islamitische geestelijke verzorgers en andere professionals": {"tr": "İslami manevi danışmanlar ve diğer profesyoneller", "en": "Islamic spiritual caregivers and other professionals"}, "Onderwijs- en educatieprofessionals": {"tr": "Eğitim ve öğretim profesyonelleri", "en": "Education professionals"}, "Zorg- en welzijnsinstellingen": {"tr": "Sağlık ve sosyal hizmet kurumları", "en": "Care and welfare institutions"}, "Iedereen die islamitische kennis wil verbinden met het dagelijks leven": {"tr": "İslami bilgiyi günlük hayatla buluşturmak isteyen herkes", "en": "Anyone who wishes to connect Islamic knowledge with daily life"}, "De materialen, publicaties en begeleiding worden geleidelijk beschikbaar in meerdere talen, waaronder Nederlands en Turks. Waar passend zullen onderdelen ook in het Arabisch worden aangeboden.": {"tr": "Materyaller, yayınlar ve danışmanlık hizmetleri kademeli olarak Hollandaca ve Türkçe başta olmak üzere birden fazla dilde sunulacaktır. Uygun olduğu yerlerde bazı bölümler Arapça olarak da sunulacaktır.", "en": "The materials, publications and guidance will gradually become available in several languages, including Dutch and Turkish. Where appropriate, parts will also be offered in Arabic."}, "Achter Rihlaturruh": {"tr": "Rihlaturruh'un ardındaki isim", "en": "Behind Rihlaturruh"}, "Mijn naam is Havva.": {"tr": "Adım Havva.", "en": "My name is Havva."}, "Ik ben islamitisch theoloog en islamitisch geestelijk verzorger.": {"tr": "İslam ilahiyatçısı ve İslami manevi danışmanım.", "en": "I am an Islamic theologian and Islamic spiritual caregiver."}, "Ik behaalde een Bachelor of Arts (BA) in Islamitische Theologie, gevolgd door een Master of Arts (MA) in Islamitische Geestelijke Verzorging.": {"tr": "İslami İlahiyat alanında Bachelor of Arts (BA), ardından İslami Manevi Danışmanlık alanında Master of Arts (MA) derecesi aldım.", "en": "I obtained a Bachelor of Arts (BA) in Islamic Theology, followed by a Master of Arts (MA) in Islamic Spiritual Care."}, "Een bijzonder vormende periode in mijn leven bracht ik door in Al-Madinah al-Munawwarah (Medina). Daar heb ik gewoond, gestudeerd en gewerkt. De nabijheid van de Masjid an-Nabawi, de dagelijkse omgang met kennis en de spirituele omgeving van Medina hebben mijn visie op geloof, zielzorg en geestelijke verzorging blijvend gevormd.": {"tr": "Hayatımın özellikle biçimlendirici bir dönemini Medine-i Münevvere'de geçirdim. Orada yaşadım, okudum ve çalıştım. Mescid-i Nebevî'nin yakınlığı, ilimle iç içe geçen günlük hayat ve Medine'nin manevi atmosferi; imana, gönül bakımına ve manevi danışmanlığa dair bakışımı kalıcı olarak şekillendirdi.", "en": "I spent a particularly formative period of my life in Al-Madinah al-Munawwarah (Medina), where I lived, studied and worked. The nearness of the Masjid an-Nabawi, the daily engagement with knowledge and the spiritual atmosphere of Medina have permanently shaped my view of faith, care of the soul and spiritual care."}, "Die ervaringen vormen vandaag de dag de inspiratie achter Rihlaturruh. Vanuit mijn achtergrond ontwikkel ik materialen die mensen helpen stil te staan bij hun eigen levensreis — materialen die uitnodigen tot reflectie, betekenisgeving en een diepere verbinding met Allah.": {"tr": "Bu deneyimler bugün Rihlaturruh'un ardındaki ilhamı oluşturuyor. Kendi altyapımdan hareketle, insanların kendi hayat yolculukları üzerine durup düşünmelerine yardımcı olan materyaller geliştiriyorum — tefekküre, anlam kazandırmaya ve Allah ile daha derin bir bağa davet eden materyaller.", "en": "Those experiences form the inspiration behind Rihlaturruh today. Drawing on my background, I develop materials that help people pause and reflect on their own life journey — materials that invite reflection, meaning-making and a deeper connection with Allah."}, "Mijn verlangen is dat Rihlaturruh mag uitgroeien tot een plek waar mensen niet alleen kennis opdoen, maar ook rust vinden, hoop hervinden en met meer bewustzijn hun eigen reis van de ziel voortzetten.": {"tr": "Dileğim, Rihlaturruh'un yalnızca bilgi edinilen değil; huzur bulunan, umudun yeniden keşfedildiği ve insanların daha bilinçli biçimde kendi ruh yolculuklarını sürdürdüğü bir yer hâline gelmesidir.", "en": "My hope is that Rihlaturruh may grow into a place where people not only gain knowledge, but also find peace, rediscover hope and continue their own journey of the soul with greater awareness."}, "Onze kernwaarden": {"tr": "Temel değerlerimiz", "en": "Our core values"}, "Authentiek": {"tr": "Özgün", "en": "Authentic"}, "Geworteld in de Koran en de authentieke Soennah.": {"tr": "Kur'an ve sahih Sünnet'e dayalı.", "en": "Rooted in the Qur'an and the authentic Sunnah."}, "Diepgaand": {"tr": "Derinlikli", "en": "Profound"}, "Ruimte voor bezinning, reflectie en betekenis.": {"tr": "Tefekküre, derin düşünmeye ve anlama alan açar.", "en": "Room for contemplation, reflection and meaning."}, "Toepasbaar": {"tr": "Uygulanabilir", "en": "Applicable"}, "Praktische materialen die aansluiten bij het dagelijks leven.": {"tr": "Günlük hayata uygun pratik materyaller.", "en": "Practical materials that fit into daily life."}, "Professioneel": {"tr": "Profesyonel", "en": "Professional"}, "Ontwikkeld vanuit islamitische theologie en geestelijke verzorging.": {"tr": "İslam ilahiyatı ve manevi danışmanlık temelinde geliştirilmiştir.", "en": "Developed from Islamic theology and spiritual care."}, "Barmhartig": {"tr": "Merhametli", "en": "Compassionate"}, "Met aandacht voor de mens achter het verhaal.": {"tr": "Hikâyenin ardındaki insana özenle yaklaşır.", "en": "With attention for the person behind the story."}, "Iedere ziel legt haar eigen reis af.": {"tr": "Her ruh kendi yolculuğunu tamamlar.", "en": "Every soul travels its own journey."}, "Mijn wens is dat Rihlaturruh een metgezel mag zijn op die reis: een plek waar kennis het hart raakt, waar reflectie leidt tot bewustwording en waar de verbinding met Allah steeds opnieuw mag worden versterkt.": {"tr": "Dileğim, Rihlaturruh'un bu yolculukta bir yoldaş olmasıdır: bilginin kalbe dokunduğu, tefekkürün farkındalığa dönüştüğü ve Allah ile bağın her defasında yeniden güçlendiği bir yer.", "en": "My wish is that Rihlaturruh may be a companion on that journey: a place where knowledge touches the heart, where reflection leads to awareness, and where the connection with Allah may be strengthened again and again."}, "Geestelijke Verzorging": {"tr": "Manevi Danışmanlık", "en": "Spiritual Care"}, "Vanuit islamitisch perspectief": {"tr": "İslami perspektiften", "en": "From an Islamic perspective"}, "Soms brengt het leven momenten met zich mee waarop woorden moeilijk te vinden zijn. Een verlies, een ingrijpende gebeurtenis, geloofsvragen of een periode van innerlijke onrust kunnen het verlangen oproepen naar een gesprek waarin ruimte is voor uw verhaal.": {"tr": "Hayat kimi zaman kelimelerin zor bulunduğu anlar getirir. Bir kayıp, sarsıcı bir olay, imana dair sorular ya da içsel huzursuzluk dönemi; hikâyenize alan açan bir sohbet arzusunu doğurabilir.", "en": "Life sometimes brings moments in which words are hard to find. A loss, a life-changing event, questions of faith or a period of inner unrest can awaken a longing for a conversation in which there is room for your story."}, "Rihlaturruh biedt geestelijke verzorging vanuit een islamitisch perspectief. In een veilige en respectvolle omgeving is er aandacht voor geloof, levensvragen en persoonlijke ervaringen. Samen zoeken we naar betekenis, veerkracht en een bewuste verbinding met Allah.": {"tr": "Rihlaturruh, İslami perspektiften manevi danışmanlık sunar. Güvenli ve saygılı bir ortamda imana, hayata dair sorulara ve kişisel deneyimlere yer verilir. Birlikte anlamı, dayanıklılığı ve Allah ile bilinçli bir bağı ararız.", "en": "Rihlaturruh offers spiritual care from an Islamic perspective. In a safe and respectful setting there is attention for faith, life questions and personal experiences. Together we search for meaning, resilience and a conscious connection with Allah."}, "Iedere begeleiding is maatwerk en sluit aan bij uw persoonlijke situatie, behoeften en levensfase.": {"tr": "Her danışmanlık süreci kişiye özeldir ve sizin durumunuza, ihtiyaçlarınıza ve hayat evrenize göre şekillenir.", "en": "Every guidance process is tailor-made and matches your personal situation, needs and stage of life."}, "Meer over mijn werkwijze →": {"tr": "Çalışma yöntemim hakkında →", "en": "More about my approach →"}, "Waarvoor kunt u terecht?": {"tr": "Hangi konularda başvurabilirsiniz?", "en": "What can you come for?"}, "Zingeving en levensvragen": {"tr": "Anlam arayışı ve hayata dair sorular", "en": "Meaning and life questions"}, "Samen stilstaan bij vragen over het leven, geloof en de zoektocht naar betekenis.": {"tr": "Hayat, iman ve anlam arayışına dair sorular üzerine birlikte düşünmek.", "en": "Pausing together on questions about life, faith and the search for meaning."}, "Geloofsbeleving en spiritualiteit": {"tr": "İman deneyimi ve maneviyat", "en": "Faith experience and spirituality"}, "Verdieping van de relatie met Allah en het versterken van een bewuste geloofsbeleving.": {"tr": "Allah ile ilişkinin derinleşmesi ve bilinçli bir iman deneyiminin güçlenmesi.", "en": "Deepening the relationship with Allah and strengthening a conscious experience of faith."}, "Persoonlijke ontwikkeling": {"tr": "Kişisel gelişim", "en": "Personal development"}, "Ruimte voor zelfreflectie, persoonlijke groei en het maken van bewuste keuzes.": {"tr": "Öz-tefekküre, kişisel gelişime ve bilinçli tercihler yapmaya alan açmak.", "en": "Room for self-reflection, personal growth and making conscious choices."}, "Verlies en ingrijpende gebeurtenissen": {"tr": "Kayıp ve sarsıcı olaylar", "en": "Loss and life-changing events"}, "Begeleiding bij verlies, ziekte, veranderingen of andere ingrijpende levensmomenten.": {"tr": "Kayıp, hastalık, değişim ya da diğer sarsıcı hayat anlarında danışmanlık.", "en": "Guidance in times of loss, illness, change or other significant life moments."}, "Innerlijke rust en veerkracht": {"tr": "İç huzur ve dayanıklılık", "en": "Inner peace and resilience"}, "Samen zoeken naar meer rust, balans en veerkracht vanuit islamitisch perspectief.": {"tr": "İslami perspektiften daha fazla huzur, denge ve dayanıklılık aramak.", "en": "Searching together for more peace, balance and resilience from an Islamic perspective."}, "Identiteit en levensfase": {"tr": "Kimlik ve hayat evresi", "en": "Identity and stage of life"}, "Vragen rondom identiteit, levensfasen en de uitdagingen die daarbij kunnen ontstaan.": {"tr": "Kimliğe, hayat evrelerine ve bunlarla gelen zorluklara dair sorular.", "en": "Questions around identity, stages of life and the challenges they may bring."}, "Iedere begeleiding is maatwerk en wordt afgestemd op uw persoonlijke situatie, hulpvraag en behoeften.": {"tr": "Her danışmanlık süreci kişiye özeldir; durumunuza, talebinize ve ihtiyaçlarınıza göre düzenlenir.", "en": "Every guidance process is tailor-made and adapted to your personal situation, question and needs."}, "Staat uw vraag hier niet tussen? Ook dan bent u van harte welkom voor een vrijblijvend kennismakingsgesprek. Samen bekijken we welke vorm van begeleiding het beste aansluit bij uw situatie.": {"tr": "Sorunuz burada yer almıyor mu? O hâlde de tanışma görüşmesi için gönülden davetlisiniz; herhangi bir yükümlülüğü yoktur. Durumunuza en uygun danışmanlık biçimini birlikte değerlendiririz.", "en": "Is your question not listed here? You are just as welcome for a no-obligation introductory conversation. Together we will look at which form of guidance best suits your situation."}, "Werkwijze": {"tr": "Çalışma yöntemi", "en": "Approach"}, "Een begeleidingsgesprek biedt een veilige en vertrouwelijke omgeving waarin ruimte is voor uw verhaal, reflectie en bezinning.": {"tr": "Bir danışmanlık görüşmesi; hikâyenize, tefekküre ve iç muhasebeye alan açan güvenli ve gizliliğe saygılı bir ortam sunar.", "en": "A guidance conversation offers a safe and confidential setting with room for your story, reflection and contemplation."}, "Wanneer dit passend is bij uw hulpvraag, kunnen reflectiewerkbladen en andere materialen van Rihlaturruh worden ingezet ter ondersteuning van het gesprek.": {"tr": "Talebinize uygun olduğunda, görüşmeyi desteklemek için Rihlaturruh'un tefekkür çalışma sayfaları ve diğer materyalleri kullanılabilir.", "en": "Where it suits your question, Rihlaturruh's reflection worksheets and other materials can be used to support the conversation."}, "Tijdens de begeleiding kan onder andere gebruik worden gemaakt van:": {"tr": "Danışmanlık sürecinde başlıca şunlardan yararlanılabilir:", "en": "During the guidance, use may be made of, among others:"}, "Reflectievragen": {"tr": "Tefekkür soruları", "en": "Reflection questions"}, "Islamitische bronnen": {"tr": "İslami kaynaklar", "en": "Islamic sources"}, "Koranverzen en authentieke ahadith": {"tr": "Kur'an ayetleri ve sahih hadisler", "en": "Qur'anic verses and authentic ahadith"}, "Reflectiematerialen van Rihlaturruh": {"tr": "Rihlaturruh'un tefekkür materyalleri", "en": "Reflection materials from Rihlaturruh"}, "Praktische oefeningen": {"tr": "Pratik alıştırmalar", "en": "Practical exercises"}, "De begeleiding wordt verzorgd door mij, Havva, islamitisch theoloog en islamitisch geestelijk verzorger. Vanuit mijn academische achtergrond en praktijkervaring bied ik begeleiding waarin geloof, reflectie en persoonlijke aandacht samenkomen.": {"tr": "Danışmanlık, İslam ilahiyatçısı ve İslami manevi danışman olarak benim, Havva, tarafından verilmektedir. Akademik altyapım ve saha deneyimimden hareketle; imanın, tefekkürün ve kişisel ilginin buluştuğu bir danışmanlık sunuyorum.", "en": "The guidance is provided by me, Havva, Islamic theologian and Islamic spiritual caregiver. Drawing on my academic background and practical experience, I offer guidance in which faith, reflection and personal attention come together."}, "Talen": {"tr": "Diller", "en": "Languages"}, "Begeleidingsgesprekken kunnen worden aangeboden in:": {"tr": "Danışmanlık görüşmeleri şu dillerde sunulabilir:", "en": "Guidance conversations can be offered in:"}, "Nederlands": {"tr": "Hollandaca", "en": "Dutch"}, "En eventueel Engels en Arabisch.": {"tr": "Ayrıca gerektiğinde İngilizce ve Arapça.", "en": "And, if needed, English and Arabic."}, "Een afspraak maken": {"tr": "Randevu almak", "en": "Making an appointment"}, "Wilt u een gesprek aanvragen of heeft u vragen? Neem gerust contact op via het contactformulier of stuur een e-mail. Samen bekijken we welke vorm van begeleiding het beste aansluit bij uw vraag.": {"tr": "Bir görüşme talep etmek ister misiniz ya da sorularınız mı var? İletişim formu üzerinden ulaşabilir veya e-posta gönderebilirsiniz. Talebinize en uygun danışmanlık biçimini birlikte değerlendiririz.", "en": "Would you like to request a conversation or do you have questions? Feel free to get in touch via the contact form or send an email. Together we will look at which form of guidance best suits your question."}, "Neem contact op": {"tr": "İletişime geçin", "en": "Get in touch"}, "Of stuur een e-mail": {"tr": "Ya da e-posta gönderin", "en": "Or send an email"}, "Iedere levensreis kent momenten waarop het helpend is om samen stil te staan.": {"tr": "Her hayat yolculuğunda, birlikte durup düşünmenin iyi geldiği anlar vardır.", "en": "Every life journey has moments in which it helps to pause together."}, "Ik nodig u uit om contact op te nemen. Ik kijk ernaar uit om met u mee te denken.": {"tr": "Sizi iletişime geçmeye davet ediyorum. Sizinle birlikte düşünmeyi dört gözle bekliyorum.", "en": "I invite you to get in touch. I look forward to thinking along with you."}, "Materialen die uitnodigen tot bezinning": {"tr": "Tefekküre davet eden materyaller", "en": "Materials that invite contemplation"}, "De reflectiematerialen van Rihlaturruh zijn ontwikkeld om ruimte te creëren voor reflectie, bewustwording en betekenisgeving vanuit islamitisch perspectief.": {"tr": "Rihlaturruh'un tefekkür materyalleri; İslami perspektiften tefekküre, farkındalığa ve anlam kazandırmaya alan açmak için geliştirilmiştir.", "en": "Rihlaturruh's reflection materials are developed to create space for reflection, awareness and meaning-making from an Islamic perspective."}, "Elke werkvorm is met zorg samengesteld en kan worden gebruikt voor persoonlijke bezinning, tijdens begeleiding of binnen een professionele context.": {"tr": "Her çalışma biçimi özenle hazırlanmıştır; kişisel tefekkür için, danışmanlık sürecinde ya da profesyonel bir bağlamda kullanılabilir.", "en": "Each format is carefully composed and can be used for personal contemplation, during guidance, or within a professional context."}, "Wat Rihlaturruh ontwikkelt": {"tr": "Rihlaturruh neler geliştiriyor", "en": "What Rihlaturruh develops"}, "Reflectiewerkbladen": {"tr": "Tefekkür çalışma sayfaları", "en": "Reflection worksheets"}, "Werkvormen die uitnodigen tot zelfreflectie en verdieping.": {"tr": "Öz-tefekküre ve derinleşmeye davet eden çalışma biçimleri.", "en": "Formats that invite self-reflection and depth."}, "Posters": {"tr": "Posterler", "en": "Posters"}, "Visuele reminders voor inspiratie en bezinning in het dagelijks leven.": {"tr": "Günlük hayatta ilham ve tefekkür için görsel hatırlatıcılar.", "en": "Visual reminders for inspiration and contemplation in daily life."}, "E-books": {"tr": "E-kitaplar", "en": "E-books"}, "Verdiepende uitgaven over thema’s die raken aan het hart en de ziel.": {"tr": "Kalbe ve ruha dokunan temalar üzerine derinlikli yayınlar.", "en": "In-depth publications on themes that touch the heart and the soul."}, "Digitale hulpmiddelen": {"tr": "Dijital araçlar", "en": "Digital tools"}, "Digitale werkbladen, invulbare PDF’s en reflectie-oefeningen voor flexibel gebruik.": {"tr": "Esnek kullanım için dijital çalışma sayfaları, doldurulabilir PDF'ler ve tefekkür alıştırmaları.", "en": "Digital worksheets, fillable PDFs and reflection exercises for flexible use."}, "Voor persoonlijk én professioneel gebruik": {"tr": "Hem kişisel hem profesyonel kullanım için", "en": "For personal and professional use"}, "De materialen zijn geschikt voor persoonlijke reflectie en kunnen daarnaast worden ingezet door islamitisch geestelijk verzorgers, docenten, zorgprofessionals en begeleiders die werken met moslims. Afhankelijk van de inhoud zijn ze toepasbaar binnen onderwijs, geestelijke verzorging en de zorg — en worden ze geleidelijk beschikbaar in meerdere talen, waaronder Nederlands en Turks.": {"tr": "Materyaller kişisel tefekkür için uygundur; ayrıca Müslümanlarla çalışan İslami manevi danışmanlar, öğretmenler, sağlık profesyonelleri ve rehberler tarafından da kullanılabilir. İçeriğine bağlı olarak eğitim, manevi danışmanlık ve sağlık alanlarında uygulanabilirler — ve kademeli olarak Hollandaca ve Türkçe başta olmak üzere birden fazla dilde sunulacaktır.", "en": "The materials are suitable for personal reflection and can also be used by Islamic spiritual caregivers, teachers, care professionals and mentors working with Muslims. Depending on the content, they are applicable within education, spiritual care and healthcare — and are gradually becoming available in several languages, including Dutch and Turkish."}, "Met zorg ontwikkeld": {"tr": "Özenle geliştirildi", "en": "Developed with care"}, "Iedere uitgave is gebaseerd op islamitische bronnen en geschreven met aandacht voor reflectie, toegankelijkheid en praktische toepasbaarheid. Het doel is niet alleen om kennis over te dragen, maar ook om stil te staan bij de vragen, ervaringen en momenten die deel uitmaken van de reis van de ziel. Wij geloven dat reflectie begint met vertragen.": {"tr": "Her yayın İslami kaynaklara dayanır ve tefekküre, erişilebilirliğe ve pratik uygulanabilirliğe özen gösterilerek yazılır. Amaç yalnızca bilgi aktarmak değil; ruhun yolculuğunun parçası olan sorular, deneyimler ve anlar üzerinde durup düşünmektir. Tefekkürün yavaşlamakla başladığına inanıyoruz.", "en": "Every publication is based on Islamic sources and written with attention to reflection, accessibility and practical applicability. The aim is not only to convey knowledge, but also to pause at the questions, experiences and moments that are part of the journey of the soul. We believe that reflection begins with slowing down."}, "Niet ieder antwoord begint met spreken. Soms begint het met stil durven staan.": {"tr": "Her cevap konuşmakla başlamaz. Kimi zaman durup düşünmeye cesaret etmekle başlar.", "en": "Not every answer begins with speaking. Sometimes it begins with daring to pause."}, "Ontdek de materialen": {"tr": "Materyalleri keşfedin", "en": "Discover the materials"}, "Reflectiematerialen die je ondersteunen op jouw reis van de ziel. Interesse of vroege toegang?": {"tr": "Ruh yolculuğunuzda sizi destekleyen tefekkür materyalleri. İlgileniyor musunuz ya da erken erişim ister misiniz?", "en": "Reflection materials that support you on your journey of the soul. Interested, or would you like early access?"}, "Heeft u een vraag, wilt u meer informatie of bent u benieuwd wat Rihlaturruh voor u of uw organisatie kan betekenen?": {"tr": "Bir sorunuz mu var, daha fazla bilgi mi almak istiyorsunuz ya da Rihlaturruh'un sizin veya kurumunuz için ne ifade edebileceğini mi merak ediyorsunuz?", "en": "Do you have a question, would you like more information, or are you curious what Rihlaturruh could mean for you or your organisation?"}, "U bent van harte welkom om contact op te nemen. Ik neem de tijd om ieder bericht zorgvuldig te lezen en streef ernaar zo spoedig mogelijk te reageren.": {"tr": "İletişime geçmeniz bizi mutlu eder. Her mesajı dikkatle okumaya zaman ayırıyor ve en kısa sürede yanıt vermeye özen gösteriyorum.", "en": "You are very welcome to get in touch. I take the time to read every message carefully and aim to respond as soon as possible."}, "Contactgegevens": {"tr": "İletişim bilgileri", "en": "Contact details"}, "E-mail": {"tr": "E-posta", "en": "Email"}, "Voor vragen, informatie of het aanvragen van een begeleidingsgesprek.": {"tr": "Sorular, bilgi talebi ya da danışmanlık görüşmesi randevusu için.", "en": "For questions, information or requesting a guidance conversation."}, "Dagelijkse inspiratie, reflecties en updates.": {"tr": "Günlük ilham, tefekkürler ve güncellemeler.", "en": "Daily inspiration, reflections and updates."}, "Contactformulier": {"tr": "İletişim formu", "en": "Contact form"}, "Heeft u een vraag of wilt u meer informatie? Vul onderstaand formulier in. Ik neem zo spoedig mogelijk contact met u op.": {"tr": "Bir sorunuz mu var ya da daha fazla bilgi mi istiyorsunuz? Aşağıdaki formu doldurun. En kısa sürede sizinle iletişime geçeceğim.", "en": "Do you have a question or would you like more information? Fill in the form below. I will contact you as soon as possible."}, "Onderwerp": {"tr": "Konu", "en": "Subject"}, "Algemene vraag": {"tr": "Genel soru", "en": "General question"}, "Begeleidingsgesprek": {"tr": "Danışmanlık görüşmesi", "en": "Guidance conversation"}, "Samenwerking": {"tr": "İş birliği", "en": "Collaboration"}, "Anders": {"tr": "Diğer", "en": "Other"}, "Verzenden ✈": {"tr": "Gönder ✈", "en": "Send ✈"}, "Samenwerken": {"tr": "İş birliği", "en": "Working together"}, "Rihlaturruh werkt graag samen met organisaties en professionals die zich inzetten voor zingeving, educatie, geestelijke verzorging en de ontwikkeling van islamitische reflectiematerialen.": {"tr": "Rihlaturruh; anlam arayışı, eğitim, manevi danışmanlık ve İslami tefekkür materyallerinin geliştirilmesi için çalışan kurum ve profesyonellerle iş birliği yapmaktan memnuniyet duyar.", "en": "Rihlaturruh is glad to work with organisations and professionals committed to meaning, education, spiritual care and the development of Islamic reflection materials."}, "Samenwerkingen zijn onder andere mogelijk met:": {"tr": "İş birlikleri başlıca şunlarla mümkündür:", "en": "Collaborations are possible with, among others:"}, "zorginstellingen;": {"tr": "sağlık kurumları;", "en": "care institutions;"}, "onderwijsinstellingen;": {"tr": "eğitim kurumları;", "en": "educational institutions;"}, "moskeeën;": {"tr": "camiler;", "en": "mosques;"}, "maatschappelijke organisaties;": {"tr": "sivil toplum kuruluşları;", "en": "civil society organisations;"}, "islamitische geestelijk verzorgers;": {"tr": "İslami manevi danışmanlar;", "en": "Islamic spiritual caregivers;"}, "andere professionals binnen het sociale domein.": {"tr": "sosyal alanda çalışan diğer profesyoneller.", "en": "other professionals within the social domain."}, "Voor samenwerkingen of zakelijke vragen kunt u vrijblijvend contact opnemen.": {"tr": "İş birlikleri veya kurumsal sorular için çekinmeden iletişime geçebilirsiniz.", "en": "For collaborations or business enquiries, please feel free to get in touch."}, "Iedere ontmoeting begint met een eerste stap.": {"tr": "Her karşılaşma ilk adımla başlar.", "en": "Every encounter begins with a first step."}, "Ik zie ernaar uit om kennis met u te maken en samen te verkennen wat Rihlaturruh voor u kan betekenen.": {"tr": "Sizinle tanışmayı ve Rihlaturruh'un sizin için ne ifade edebileceğini birlikte keşfetmeyi dört gözle bekliyorum.", "en": "I look forward to meeting you and exploring together what Rihlaturruh can mean for you."}, "Kennis delen, verdieping brengen": {"tr": "Bilgiyi paylaşmak, derinlik katmak", "en": "Sharing knowledge, bringing depth"}, "De onderzoeksresultaten van beide scripties zijn nu interactief te bekijken. Toegankelijke samenvattingen volgen stap voor stap.": {"tr": "Her iki tezin araştırma sonuçları artık etkileşimli olarak incelenebilir. Erişilebilir özetler adım adım eklenecektir.", "en": "The research results of both theses can now be explored interactively. Accessible summaries will follow step by step."}, "Masterscriptie · Onderzoeksresultaten": {"tr": "Yüksek lisans tezi · Araştırma sonuçları", "en": "Master's thesis · Research results"}, "Psycho-spirituele processen bij Nederlandse moslims": {"tr": "Hollandalı Müslümanlarda psiko-spiritüel süreçler", "en": "Psycho-spiritual processes among Dutch Muslims"}, "Een interactief overzicht van de resultaten van de enquête naar geloofsbeleving, zingeving en welbevinden.": {"tr": "İman deneyimi, anlam arayışı ve iyi oluş hâline dair anket sonuçlarının etkileşimli bir özeti.", "en": "An interactive overview of the survey results on faith experience, meaning and well-being."}, "Bekijk de resultaten →": {"tr": "Sonuçlara göz atın →", "en": "View the results →"}, "Bachelorscriptie · Onderzoeksresultaten": {"tr": "Lisans tezi · Araştırma sonuçları", "en": "Bachelor's thesis · Research results"}, "De Sportieve Moslimvrouwen": {"tr": "Sporcu Müslüman Kadınlar", "en": "The Sporting Muslim Women"}, "Een interactief overzicht van de resultaten van de enquête onder sportieve moslimvrouwen: beleving, motivatie en welbevinden.": {"tr": "Sporla ilgilenen Müslüman kadınlar arasında yapılan anketin etkileşimli özeti: deneyim, motivasyon ve iyi oluş hâli.", "en": "An interactive overview of the survey results among sporting Muslim women: experience, motivation and well-being."}, "Onderzoek & samenvattingen": {"tr": "Araştırma ve özetler", "en": "Research & summaries"}, "Toegankelijke samenvattingen en verdieping bij het onderzoek rond geloof, zingeving en geestelijke verzorging worden hier stap voor stap toegevoegd.": {"tr": "İman, anlam arayışı ve manevi danışmanlık üzerine yapılan araştırmalara dair erişilebilir özetler ve derinlikli içerikler burada adım adım eklenecektir.", "en": "Accessible summaries and further depth on the research around faith, meaning and spiritual care will be added here step by step."}, "Kennis raakt pas werkelijk als zij het hart bereikt.": {"tr": "Bilgi ancak kalbe ulaştığında gerçekten dokunur.", "en": "Knowledge truly touches only when it reaches the heart."}, "Naam": {"tr": "Ad", "en": "Name"}, "E-mailadres": {"tr": "E-posta adresi", "en": "Email address"}, "Bericht": {"tr": "Mesaj", "en": "Message"}, "26 juni 2025": {"tr": "26 Haziran 2025", "en": "26 June 2025"}, "29 mei 2025": {"tr": "29 Mayıs 2025", "en": "29 May 2025"}, "17 april 2025": {"tr": "17 Nisan 2025", "en": "17 April 2025"}, "10 april 2025": {"tr": "10 Nisan 2025", "en": "10 April 2025"}, "14 maart 2024": {"tr": "14 Mart 2024", "en": "14 March 2024"}, "29 februari 2024": {"tr": "29 Şubat 2024", "en": "29 February 2024"}, "27 februari 2024": {"tr": "27 Şubat 2024", "en": "27 February 2024"}, "19 februari 2024": {"tr": "19 Şubat 2024", "en": "19 February 2024"}, "15 februari 2024": {"tr": "15 Şubat 2024", "en": "15 February 2024"}, "12 februari 2024": {"tr": "12 Şubat 2024", "en": "12 February 2024"}, "8 februari 2024": {"tr": "8 Şubat 2024", "en": "8 February 2024"}, "25 januari 2024": {"tr": "25 Ocak 2024", "en": "25 January 2024"}, "18 januari 2024": {"tr": "18 Ocak 2024", "en": "18 January 2024"}, "28 december 2023": {"tr": "28 Aralık 2023", "en": "28 December 2023"}, "21 december 2023": {"tr": "21 Aralık 2023", "en": "21 December 2023"}, "14 december 2023": {"tr": "14 Aralık 2023", "en": "14 December 2023"}, "30 november 2023": {"tr": "30 Kasım 2023", "en": "30 November 2023"}, "23 november 2023": {"tr": "23 Kasım 2023", "en": "23 November 2023"}, "16 november 2023": {"tr": "16 Kasım 2023", "en": "16 November 2023"}, "2 november 2023": {"tr": "2 Kasım 2023", "en": "2 November 2023"}, "26 oktober 2023": {"tr": "26 Ekim 2023", "en": "26 October 2023"}, "Wat Rihlaturruh biedt": {"tr": "Rihlaturruh ne sunuyor?", "en": "What Rihlaturruh offers"}, "Vanuit een islamitisch-theologische achtergrond biedt Rihlaturruh persoonlijke begeleiding, lessen, lezingen en workshops — met aandacht voor geloof, reflectie en verdieping.": {"tr": "İslami-ilahiyat kökenli bir altyapıdan hareketle Rihlaturruh; kişisel danışmanlık, dersler, konferanslar ve atölyeler sunar — imana, tefekküre ve derinleşmeye özenle.", "en": "Drawing on a background in Islamic theology, Rihlaturruh offers personal guidance, lessons, lectures and workshops — with attention to faith, reflection and depth."}, "Personen begeleid": {"tr": "Kişiye danışmanlık verildi", "en": "People guided"}, "sinds 2020": {"tr": "2020'den beri", "en": "since 2020"}, "Tientallen": {"tr": "Onlarca", "en": "Dozens of"}, "Lessen gegeven": {"tr": "Verilen dersler", "en": "Lessons given"}, "gegeven": {"tr": "verildi", "en": "given"}, "ontwikkeld": {"tr": "geliştirildi", "en": "developed"}, "Dienst 01 · Persoonlijke begeleiding": {"tr": "Hizmet 01 · Kişisel danışmanlık", "en": "Service 01 · Personal guidance"}, "Geestelijke verzorging vanuit een islamitisch perspectief — een veilige ruimte voor uw verhaal, levensvragen en reflectie.": {"tr": "İslami perspektiften manevi danışmanlık — hikâyeniz, hayata dair sorularınız ve tefekkürünüz için güvenli bir alan.", "en": "Spiritual care from an Islamic perspective — a safe space for your story, life questions and reflection."}, "Lees meer over begeleiding →": {"tr": "Danışmanlık hakkında daha fazla bilgi →", "en": "Read more about guidance →"}, "Dienst 02 · Onderwijs": {"tr": "Hizmet 02 · Eğitim", "en": "Service 02 · Education"}, "Lessen — Arabisch & Tadjwied": {"tr": "Dersler — Arapça ve Tecvid", "en": "Lessons — Arabic & Tajwid"}, "Arabisch leren lezen en de Koran leren reciteren, voor kinderen en volwassenen, individueel of in kleine groepen.": {"tr": "Arapça okumayı ve Kur'an'ı tecvidle okumayı öğrenin — çocuklar ve yetişkinler için, bireysel ya da küçük gruplarda.", "en": "Learning to read Arabic and to recite the Qur'an, for children and adults, individually or in small groups."}, "Bekijk het lesaanbod →": {"tr": "Ders programını görüntüleyin →", "en": "View the lesson offerings →"}, "Dienst 03 · Kennis & verdieping": {"tr": "Hizmet 03 · Bilgi ve derinleşme", "en": "Service 03 · Knowledge & depth"}, "Lezingen voor dames": {"tr": "Hanımlar için konferanslar", "en": "Lectures for women"}, "Nederlandstalige lezingen sinds 2020, over thema’s die het hart raken. Bekijk het overzicht van eerder gegeven lezingen.": {"tr": "2020'den beri kalbe dokunan temalar üzerine Hollandaca konferanslar. Daha önce verilen konferansların genel görünümüne göz atın.", "en": "Dutch-language lectures since 2020, on themes that touch the heart. View the overview of previously given lectures."}, "Bekijk alle lezingen →": {"tr": "Tüm konferansları görüntüleyin →", "en": "View all lectures →"}, "Dienst 04 · Praktijkgericht": {"tr": "Hizmet 04 · Uygulama odaklı", "en": "Service 04 · Practice-based"}, "Praktijkgerichte workshops zoals Workshop Dodenwassing, Ik Leer Bidden voor Kinderen en Zaalvoetbal voor Meisjes.": {"tr": "Cenaze Yıkama Atölyesi, Çocuklar için Namaz Öğreniyorum ve Kızlar için Salon Futbolu gibi uygulama odaklı atölyeler.", "en": "Practice-based workshops such as Workshop Ritual Washing, I Learn to Pray for Children and Indoor Football for Girls."}, "Bekijk de workshops →": {"tr": "Atölyeleri görüntüleyin →", "en": "View the workshops →"}, "Terug naar Diensten & Aanbod": {"tr": "Hizmetlerimize dön", "en": "Back to Services & Offerings"}, "Diensten & Aanbod · Begeleiding": {"tr": "Hizmetlerimiz · Danışmanlık", "en": "Services & Offerings · Guidance"}, "Diensten & Aanbod · Lessen": {"tr": "Hizmetlerimiz · Dersler", "en": "Services & Offerings · Lessons"}, "Diensten & Aanbod · Lezingen": {"tr": "Hizmetlerimiz · Konferanslar", "en": "Services & Offerings · Lectures"}, "Diensten & Aanbod · Workshops": {"tr": "Hizmetlerimiz · Atölyeler", "en": "Services & Offerings · Workshops"}, "Stap voor stap de Arabische taal leren lezen en de Koran leren reciteren volgens de regels van tadjwied — voor kinderen en volwassenen, beginners en gevorderden.": {"tr": "Arapça'yı adım adım okumayı ve Kur'an'ı tecvid kurallarına göre okumayı öğrenin — çocuklar ve yetişkinler için, yeni başlayanlardan ileri seviyeye.", "en": "Learning step by step to read Arabic and to recite the Qur'an according to the rules of tajwid — for children and adults, beginners and advanced."}, "Arabisch lezen": {"tr": "Arapça okuma", "en": "Reading Arabic"}, "De Arabische letters en klanken leren herkennen en verbinden tot woorden — de basis om zelfstandig de Koran te kunnen lezen.": {"tr": "Arap harflerini ve seslerini tanımayı ve kelimelere birleştirmeyi öğrenin — Kur'an'ı bağımsız olarak okuyabilmenin temeli.", "en": "Learning to recognise the Arabic letters and sounds and combine them into words — the basis for reading the Qur'an independently."}, "Tadjwied": {"tr": "Tecvid", "en": "Tajwid"}, "Verdieping in de regels van correcte Koranrecitatie: uitspraak, uitrekking en de melodie van de recitatie zoals overgeleverd.": {"tr": "Doğru Kur'an tilavetinin kurallarında derinleşme: telaffuz, uzatmalar ve nakledilen tilavet melodisi.", "en": "Deepening the rules of correct Qur'anic recitation: pronunciation, elongation and the melody of recitation as transmitted."}, "Voor kinderen én volwassenen": {"tr": "Hem çocuklar hem yetişkinler için", "en": "For children and adults alike"}, "Individueel of in kleine groepen": {"tr": "Bireysel ya da küçük gruplarda", "en": "Individually or in small groups"}, "Beginners en gevorderden welkom": {"tr": "Yeni başlayanlar ve ileri seviye herkes davetlidir", "en": "Beginners and advanced students welcome"}, "Locatie in overleg, ook online mogelijk": {"tr": "Lokasyon karşılıklı belirlenir, online da mümkündür", "en": "Location by arrangement, online also possible"}, "Interesse in een les? Neem contact op →": {"tr": "Bir derse ilgi duyuyor musunuz? İletişime geçin →", "en": "Interested in a lesson? Get in touch →"}, "Actueel lesrooster": {"tr": "Güncel ders programı", "en": "Current lesson schedule"}, "Wekelijkse lessen": {"tr": "Haftalık dersler", "en": "Weekly lessons"}, "De actuele lestijden voor dames, wekelijks in de Ulu Moskee. Klik op een flyer om deze te vergroten.": {"tr": "Hanımlar için güncel ders saatleri, haftalık olarak Ulu Camii'de. Büyütmek için bir afişe tıklayın.", "en": "The current lesson times for women, weekly at the Ulu Mosque. Click a flyer to enlarge it."}, "Elke maandag · 10:00–14:00 uur": {"tr": "Her Pazartesi · 10:00–14:00", "en": "Every Monday · 10:00–14:00"}, "Qur’an Lessen voor Dames": {"tr": "Hanımlar için Kur'an Dersleri", "en": "Qur'an Lessons for Women"}, "Elke donderdag · 10:30–13:30 uur": {"tr": "Her Perşembe · 10:30–13:30", "en": "Every Thursday · 10:30–13:30"}, "Arabisch voor Dames": {"tr": "Hanımlar için Arapça", "en": "Arabic for Women"}, "Wie de Koran leert lezen, opent een deur die nooit meer sluit.": {"tr": "Kur'an'ı okumayı öğrenen kişi, asla kapanmayan bir kapı açar.", "en": "Whoever learns to read the Qur'an opens a door that never closes."}, "Sinds 2020 verzorg ik geregeld lezingen en bijeenkomsten over thema’s die het hart raken — van geloofsbeleving en dankbaarheid tot geduld en vertrouwen op Allah. Hieronder een overzicht van eerder gegeven lezingen, met de meest recente bovenaan. Klik op een flyer om deze te vergroten.": {"tr": "2020'den beri kalbe dokunan temalar üzerine düzenli olarak konferanslar ve buluşmalar veriyorum — iman deneyiminden şükrana, sabırdan Allah'a tevekküle kadar. Aşağıda, en yenisi en üstte olacak şekilde daha önce verilen konferansların bir listesi bulunmaktadır. Büyütmek için bir afişe tıklayın.", "en": "Since 2020 I regularly give lectures and gatherings on themes that touch the heart — from faith experience and gratitude to patience and trust in Allah. Below is an overview of previously given lectures, with the most recent at the top. Click a flyer to enlarge it."}, "Ziekten van het Hart en de Weg naar Genezing — Deel II": {"tr": "Kalbin Hastalıkları ve Şifa Yolu — Bölüm II", "en": "Diseases of the Heart and the Path to Healing — Part II"}, "Ziekten van het Hart en de Weg naar Genezing — Deel I": {"tr": "Kalbin Hastalıkları ve Şifa Yolu — Bölüm I", "en": "Diseases of the Heart and the Path to Healing — Part I"}, "Het Hart Vrij van Dunya": {"tr": "Dünyadan Azade Bir Kalp", "en": "The Heart Free from Dunya (the World)"}, "Vertrouwen op Allah (Tawakkul)": {"tr": "Allah'a Tevekkül", "en": "Trust in Allah (Tawakkul)"}, "Iftar voor Dames": {"tr": "Hanımlar için İftar", "en": "Iftar for Women"}, "De Zuivere Aanbidding en de Aanwezigheid van de Intentie": {"tr": "Halis İbadet ve Niyetin Bilinci", "en": "Sincere Worship and the Presence of Intention"}, "De Kracht van Geduld (Sabr)": {"tr": "Sabrın Gücü", "en": "The Power of Patience (Sabr)"}, "De Kracht van Dankbaarheid": {"tr": "Şükrün Gücü", "en": "The Power of Gratitude"}, "Houden van de Profeet Mohammed (vzmh)": {"tr": "Peygamber Efendimiz'i (s.a.v.) Sevmek", "en": "Loving the Prophet Muhammad (peace be upon him)"}, "Betrouwbaarheid & Het Nakomen van Beloftes": {"tr": "Güvenilirlik ve Sözünde Durmak", "en": "Trustworthiness & Keeping Promises"}, "Zusteravond — Islam Quiz": {"tr": "Kız Kardeşler Gecesi — İslam Bilgi Yarışması", "en": "Sisters' Evening — Islam Quiz"}, "Leven in en met Hoop": {"tr": "Umutla ve Umut İçinde Yaşamak", "en": "Living in and with Hope"}, "Godsvrees": {"tr": "Allah Korkusu (Takva)", "en": "God-Consciousness (Taqwa)"}, "Houden van Allah": {"tr": "Allah'ı Sevmek", "en": "Loving Allah"}, "Zusteravond — Çiğköfte": {"tr": "Kız Kardeşler Gecesi — Çiğköfte", "en": "Sisters' Evening — Çiğköfte"}, "Ontbijt voor het Goede Doel": {"tr": "Hayır İçin Kahvaltı", "en": "Breakfast for Charity"}, "Geloven in het Lot": {"tr": "Kadere İman", "en": "Belief in Fate (Qadar)"}, "Geloven in de Laatste Dag — Deel II": {"tr": "Ahiret Gününe İman — Bölüm II", "en": "Belief in the Last Day — Part II"}, "Geloven in de Laatste Dag — Deel I": {"tr": "Ahiret Gününe İman — Bölüm I", "en": "Belief in the Last Day — Part I"}, "Geloven in de Boeken en Boodschappers": {"tr": "Kitaplara ve Peygamberlere İman", "en": "Belief in the Books and Messengers"}, "Geloven in de Engelen": {"tr": "Meleklere İman", "en": "Belief in the Angels"}, "Wekelijks · iedere donderdag": {"tr": "Haftalık · her Perşembe", "en": "Weekly · every Thursday"}, "Nederlandstalige Lezing voor Dames": {"tr": "Hanımlar için Hollandaca Konferans", "en": "Dutch-language Lecture for Women"}, "Een lezing aanvragen?": {"tr": "Bir konferans talep etmek ister misiniz?", "en": "Request a lecture?"}, "Wilt u een lezing organiseren voor uw moskee, organisatie of vriendinnengroep? Neem gerust contact op om de mogelijkheden te bespreken.": {"tr": "Camininiz, kurumunuz ya da arkadaş grubunuz için bir konferans düzenlemek ister misiniz? Olanakları görüşmek için çekinmeden iletişime geçin.", "en": "Would you like to organise a lecture for your mosque, organisation or group of friends? Feel free to get in touch to discuss the possibilities."}, "Naast lezingen verzorg ik ook praktijkgerichte workshops, waarin kennis direct wordt vertaald naar de praktijk.": {"tr": "Konferansların yanı sıra, bilginin doğrudan uygulamaya dönüştüğü uygulama odaklı atölyeler de veriyorum.", "en": "Besides lectures, I also offer practice-based workshops in which knowledge is directly translated into practice."}, "Ladies only": {"tr": "Sadece hanımlar", "en": "Ladies only"}, "Workshop Dodenwassing": {"tr": "Cenaze Yıkama Atölyesi", "en": "Workshop: Ritual Washing (Dodenwassing)"}, "Een praktische workshop in twee delen waarin de dodenwassing (ghusl al-mayyit) stap voor stap wordt behandeld: van de islamitische grondslag tot de daadwerkelijke uitvoering. Bij aanwezigheid bij beide lessen wordt een certificaat uitgereikt.": {"tr": "Cenaze yıkamanın (gusl el-meyyit) adım adım ele alındığı iki bölümden oluşan pratik bir atölye: İslami temelinden fiilî uygulamaya kadar. Her iki derse de katılım sağlandığında bir sertifika verilir.", "en": "A practical workshop in two parts in which the ritual washing of the deceased (ghusl al-mayyit) is covered step by step: from the Islamic foundation to the actual practice. A certificate is awarded upon attendance of both sessions."}, "Voor kinderen": {"tr": "Çocuklar için", "en": "For children"}, "Ik Leer Bidden voor Kinderen": {"tr": "Çocuklar için Namaz Öğreniyorum", "en": "I Learn to Pray, for Children"}, "Een laagdrempelige en speelse workshop die kinderen wegwijs maakt in het gebed (salaah) — van de betekenis van de bewegingen tot het aanleren van de korte soera’s.": {"tr": "Çocukları namaza (salah) eğlenceli bir şekilde tanıştıran, kolay erişilebilir bir atölye — hareketlerin anlamından kısa surelerin öğrenilmesine kadar.", "en": "An accessible and playful workshop that introduces children to prayer (salah) — from the meaning of the movements to learning the short surahs."}, "Leeftijdsgrens 10+": {"tr": "Yaş sınırı 10+", "en": "Age limit 10+"}, "Zaalvoetbal voor Meisjes": {"tr": "Kızlar için Salon Futbolu", "en": "Indoor Football for Girls"}, "Een sportieve en gezellige activiteit waarbij meisjes onder begeleiding samen zaalvoetballen — goed voor beweging, teamgeest en onderling contact.": {"tr": "Kızların rehberlik eşliğinde birlikte salon futbolu oynadığı sportif ve keyifli bir etkinlik — hareket, takım ruhu ve karşılıklı iletişim için güzel bir fırsat.", "en": "A sporty and enjoyable activity in which girls play indoor football together under supervision — good for exercise, team spirit and connecting with one another."}, "Een workshop aanvragen?": {"tr": "Bir atölye talep etmek ister misiniz?", "en": "Request a workshop?"}, "Interesse in een van de workshops voor uw groep of organisatie? Neem gerust contact op om de mogelijkheden te bespreken.": {"tr": "Grubunuz veya kurumunuz için atölyelerden biriyle ilgileniyor musunuz? Olanakları görüşmek için çekinmeden iletişime geçin.", "en": "Interested in one of the workshops for your group or organisation? Feel free to get in touch to discuss the possibilities."}, "In ontwikkeling": {"tr": "Geliştiriliyor", "en": "In development"}, "Deze materialen worden op dit moment zorgvuldig ontwikkeld en zijn nog niet beschikbaar. Hieronder alvast een voorproefje van wat u kunt verwachten.": {"tr": "Bu materyaller şu anda özenle geliştirilmektedir ve henüz mevcut değildir. Aşağıda, sizi nelerin beklediğine dair şimdiden bir ön izleme bulabilirsiniz.", "en": "These materials are currently being carefully developed and are not yet available. Below is a preview of what you can expect."}, "Binnenkort": {"tr": "Yakında", "en": "Coming soon"}, "Meer hierover →": {"tr": "Daha fazla bilgi →", "en": "More about this →"}, "Blijf op de hoogte": {"tr": "Haberdar olun", "en": "Stay updated"}, "De reflectiematerialen zijn in ontwikkeling en volgen binnenkort. Wilt u een seintje zodra ze beschikbaar zijn, of vroege toegang?": {"tr": "Tefekkür materyalleri geliştirilme aşamasındadır ve yakında sunulacaktır. Materyaller kullanıma sunulduğunda haber almak ya da erken erişim ister misiniz?", "en": "The reflection materials are in development and will follow soon. Would you like a heads-up once they're available, or early access?"}, "Laat het mij weten": {"tr": "Bana haber verin", "en": "Let me know"}, "De materialen worden ontwikkeld voor persoonlijke reflectie en zullen daarnaast ingezet kunnen worden door islamitisch geestelijk verzorgers, docenten, zorgprofessionals en begeleiders die werken met moslims. Afhankelijk van de inhoud worden ze toepasbaar binnen onderwijs, geestelijke verzorging en de zorg — en komen ze geleidelijk beschikbaar in meerdere talen, waaronder Nederlands en Turks.": {"tr": "Materyaller kişisel tefekkür için geliştirilmektedir ve ayrıca Müslümanlarla çalışan İslami manevi danışmanlar, öğretmenler, sağlık profesyonelleri ve rehberler tarafından da kullanılabilecektir. İçeriğine bağlı olarak eğitim, manevi danışmanlık ve sağlık alanlarında uygulanabilir hâle gelecek — ve kademeli olarak Hollandaca ve Türkçe başta olmak üzere birden fazla dilde sunulacaktır.", "en": "The materials are being developed for personal reflection and will also be usable by Islamic spiritual caregivers, teachers, care professionals and mentors working with Muslims. Depending on the content, they will become applicable within education, spiritual care and healthcare — and will gradually become available in several languages, including Dutch and Turkish."}, "Zorgvuldigheid boven snelheid": {"tr": "Hız Değil, Özen", "en": "Care over speed"}, "Waardevolle reflectiematerialen ontstaan niet van de ene op de andere dag. Rihlaturruh neemt bewust de tijd om elke uitgave te laten rijpen: gegrond in de Koran en de Soennah, getoetst in de praktijk en geschreven vanuit de wens om daadwerkelijk bij te dragen aan innerlijke rust, bezinning en groei.": {"tr": "Değerli tefekkür materyalleri bir günde ortaya çıkmaz. Rihlaturruh, her yayının olgunlaşması için bilinçli olarak zaman ayırır: Kur'an ve Sünnet'e dayalı, pratikte sınanmış ve içsel huzura, tefekküre ve gelişime gerçekten katkı sağlama isteğiyle yazılmış.", "en": "Valuable reflection materials don't come together overnight. Rihlaturruh deliberately takes the time to let each publication mature: grounded in the Qur'an and the Sunnah, tested in practice, and written from the wish to genuinely contribute to inner peace, reflection and growth."}, "Liever gedegen dan gehaast — ook als dat betekent dat we u nog even geduld vragen. Zodra de eerste materialen klaar zijn, leest u het hier het eerst.": {"tr": "Aceleye getirmek yerine sağlam temelli olmayı tercih ediyoruz — bu, sizden biraz daha sabır istemek anlamına gelse bile. İlk materyaller hazır olduğunda, bunu ilk burada okuyacaksınız.", "en": "We'd rather do it thoroughly than rush it — even if that means asking you for a little more patience. As soon as the first materials are ready, you'll read it here first."}, "Reflectiematerialen voor persoonlijk en professioneel gebruik — momenteel zorgvuldig in ontwikkeling.": {"tr": "Kişisel ve profesyonel kullanım için tefekkür materyalleri — şu anda özenle geliştirilmektedir.", "en": "Reflection materials for personal and professional use — currently being carefully developed."}, "Sinds 2020 verzorg ik geregeld lezingen en bijeenkomsten over thema’s die het hart raken — van geloofsbeleving en dankbaarheid tot geduld en vertrouwen op Allah. Hieronder een overzicht van eerder gegeven lezingen, per jaar georganiseerd met het meest recente jaar bovenaan. Klik op een flyer om deze te vergroten.": {"tr": "2020'den beri kalbe dokunan temalar üzerine düzenli olarak dersler ve buluşmalar veriyorum — inanç ve şükürden sabır ve Allah'a tevekküle kadar. Aşağıda, en son yıl en üstte olacak şekilde yıllara göre düzenlenmiş, daha önce verilen derslerin bir listesi bulunmaktadır. Büyütmek için bir afişe tıklayın.", "en": "Since 2020 I regularly give lectures and gatherings on themes that touch the heart — from faith and gratitude to patience and trust in Allah. Below is an overview of past lectures, organised by year with the most recent year at the top. Click a flyer to enlarge it."}, "2026": {"tr": "2026", "en": "2026"}, "2025": {"tr": "2025", "en": "2025"}, "2024": {"tr": "2024", "en": "2024"}, "2023": {"tr": "2023", "en": "2023"}, "6 lezingen": {"tr": "6 ders", "en": "6 lectures"}, "10 lezingen": {"tr": "10 ders", "en": "10 lectures"}, "9 lezingen": {"tr": "9 ders", "en": "9 lectures"}, "29 juni 2026": {"tr": "29 Haziran 2026", "en": "29 June 2026"}, "De Eerste Mens, de Eerste Les — Profeet Adam": {"tr": "İlk İnsan, İlk Ders — Hz. Âdem", "en": "The First Human, the First Lesson — Prophet Adam"}, "1 juni 2026": {"tr": "1 Haziran 2026", "en": "1 June 2026"}, "Islamitische Lezing — Goede Moraal / Goed Gedrag": {"tr": "İslami Ders — Güzel Ahlak / İyi Davranış", "en": "Islamic Lecture — Good Morals / Good Conduct"}, "11 mei 2026": {"tr": "11 Mayıs 2026", "en": "11 May 2026"}, "De Mooiste Dagen van het Jaar — Over de Maand Dhul Hijjah": {"tr": "Yılın En Güzel Günleri — Zilhicce Ayı Üzerine", "en": "The Most Beautiful Days of the Year — On the Month of Dhul Hijjah"}, "6 april 2026": {"tr": "6 Nisan 2026", "en": "6 April 2026"}, "De Hijab, Eer Dan Wat Je Draagt?": {"tr": "Başörtüsü, Giydiğinizden Daha Fazlası mı?", "en": "The Hijab, More Than What You Wear?"}, "2 februari 2026": {"tr": "2 Şubat 2026", "en": "2 February 2026"}, "Een Maand die Jou Vormt — Groeien naar Beter": {"tr": "Sizi Şekillendiren Bir Ay — Daha İyiye Doğru Büyümek", "en": "A Month That Shapes You — Growing for the Better"}, "5 januari 2026": {"tr": "5 Ocak 2026", "en": "5 January 2026"}, "Het Leven van Fatima — De Dochter van de Profeet": {"tr": "Fatıma'nın Hayatı — Peygamberin Kızı", "en": "The Life of Fatima — The Daughter of the Prophet"}, "12 december 2025": {"tr": "12 Aralık 2025", "en": "12 December 2025"}, "Gönülden Kardeşlik — Sohbetavond": {"tr": "Gönülden Kardeşlik — Sohbet Gecesi", "en": "Sisterhood from the Heart — Sohbet Evening"}, "6 december 2025": {"tr": "6 Aralık 2025", "en": "6 December 2025"}, "De Identiteit van de Moslima op Sociale Media": {"tr": "Sosyal Medyada Müslüman Kadının Kimliği", "en": "The Identity of the Muslim Woman on Social Media"}, "11 januari 2024": {"tr": "11 Ocak 2024", "en": "11 January 2024"}, "Houden omwille van Allah": {"tr": "Allah Rızası İçin Sevmek", "en": "Loving for the Sake of Allah"}};
(function(){
  var LANGS=['nl','tr','en'], cur='nl';
  function norm(t){return t.replace(/\s+/g,' ').trim();}
  function collect(){
    var out=[], w=document.createTreeWalker(document.body,NodeFilter.SHOW_TEXT,{acceptNode:function(n){
      var p=n.parentNode; if(!p) return NodeFilter.FILTER_REJECT;
      var tag=p.nodeName.toLowerCase();
      if(tag==='script'||tag==='style') return NodeFilter.FILTER_REJECT;
      if(p.closest && p.closest('.langsw')) return NodeFilter.FILTER_REJECT;
      return norm(n.nodeValue)?NodeFilter.FILTER_ACCEPT:NodeFilter.FILTER_REJECT;
    }});
    var n; while(n=w.nextNode()) out.push(n);
    return out;
  }
  var nodes=null, orig=new WeakMap();
  var attrEls=null, attrOrig=new WeakMap();
  function init(){
    nodes=collect();
    nodes.forEach(function(n){orig.set(n,n.nodeValue);});
    attrEls=Array.prototype.slice.call(document.querySelectorAll('[placeholder]'));
    attrEls.forEach(function(e){attrOrig.set(e,e.getAttribute('placeholder'));});
  }
  function apply(lang){
    if(!nodes) init();
    cur=lang;
    nodes.forEach(function(n){
      var o=orig.get(n); if(o==null) return;
      if(lang==='nl'){ n.nodeValue=o; return; }
      var key=norm(o);
      var e=I18N[key];
      if(e&&e[lang]){
        var lead=(o.match(/^\s*/)||[''])[0];
        var trail=(o.match(/\s*$/)||[''])[0];
        n.nodeValue=lead+e[lang]+trail;
      } else {
        n.nodeValue=o;
      }
    });
    attrEls.forEach(function(el){
      var o=attrOrig.get(el); if(o==null) return;
      if(lang==='nl'){ el.setAttribute('placeholder',o); return; }
      var e=I18N[norm(o)];
      el.setAttribute('placeholder', (e&&e[lang])?e[lang]:o);
    });
    document.documentElement.lang=lang;
    document.querySelectorAll('.langsw button').forEach(function(b){
      b.classList.toggle('active', b.getAttribute('data-lang')===lang);
    });
    try{localStorage.setItem('rr_lang',lang);}catch(err){}
  }
  document.addEventListener('click',function(ev){
    var b=ev.target.closest && ev.target.closest('.langsw button');
    if(!b) return;
    ev.preventDefault();
    apply(b.getAttribute('data-lang'));
  });
  function boot(){
    init();
    var saved=null; try{saved=localStorage.getItem('rr_lang');}catch(err){}
    if(saved&&LANGS.indexOf(saved)>-1&&saved!=='nl') apply(saved);
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',boot); else boot();
  window.__setLang=apply;
})();
